import React, { useState } from "react";
import FriendsList from "./FriendsList";
import ChatPage from "./ChatPage";

function App() {
  const [userId, setUserId] = useState("");
  const [password, setPassword] = useState("");
  const [loggedIn, setLoggedIn] = useState(false);
  const [friends, setFriends] = useState([]);
  const [activeChat, setActiveChat] = useState(null);

  const register = async () => {
    const res = await fetch("http://localhost:3001/register", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ userId, password }),
    });
    alert(await res.text());
  };

  const login = async () => {
    const res = await fetch("http://localhost:3001/login", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ userId, password }),
    });
    const data = await res.text();
    if (data.includes("successful")) {
      setLoggedIn(true);
      const resUsers = await fetch(`http://localhost:3001/users/${userId}`);
      const userData = await resUsers.json();
      setFriends(userData.friends || []);
    } else {
      alert("Login failed");
    }
  };

  if (!loggedIn) {
    return (
      <div style={{ padding: "20px", textAlign: "center" }}>
        <h2>Login / Register</h2>
        <input value={userId} onChange={e => setUserId(e.target.value)} placeholder="User ID" /><br />
        <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" /><br />
        <button onClick={register}>Register</button>
        <button onClick={login} style={{ marginLeft: "10px" }}>Login</button>
      </div>
    );
  }

  if (activeChat) {
    return (
      <ChatPage
        currentUser={{ userId }}
        friend={activeChat}
        onBack={() => setActiveChat(null)}
      />
    );
  }

  return (
    <FriendsList
      friends={friends}
      currentUser={{ userId }}
      onSelectFriend={setActiveChat}
    />
  );
}

export default App;
